#!/bin/bash
set -e
echo "✨ Suggestions de collections..."
cd "$(git rev-parse --show-toplevel)"
mkdir -p src/app/api/collections/suggest src/app/api/collections/create-from-suggestion src/components/collection
python3 - << 'INNER'
import base64, os
os.makedirs("src/app/api/collections/suggest", exist_ok=True)
open("src/app/api/collections/suggest/route.ts", "wb").write(base64.b64decode(""))
os.makedirs("src/app/api/collections/create-from-suggestion", exist_ok=True)
open("src/app/api/collections/create-from-suggestion/route.ts", "wb").write(base64.b64decode(""))
os.makedirs("src/components/collection", exist_ok=True)
open("src/components/collection/SuggestModal.tsx", "wb").write(base64.b64decode(""))
os.makedirs("src/app/collections", exist_ok=True)
open("src/app/collections/page.tsx", "wb").write(base64.b64decode(""))
print("Files OK")
INNER
git add -A
git commit -m "feat: suggest collections from library — series + authors"
git push
echo "🎉 Déployé !"